4	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
5	type Step = { op: string; items: Item[] };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const STDIN_FD = 0;
9	
10	const processStep = (step: Step, yearsWithMHPCO: number): object =>
11	  step.op === "quote"
12	    ? { premium: quote({ yearsWithMHPCO, items: step.items }) }
13	    : {};
14	
15	const scenario: Scenario = JSON.parse(readFileSync(STDIN_FD, "utf-8"));
16	const results = scenario.steps.map((step) => processStep(step, scenario.customer.yearsWithMHPCO));
17	process.stdout.write(JSON.stringify({ results }));
