47	const surchargesFor = (item: Item, base: number): number => {
48	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
49	  const highEnchantment = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
50	  return curse + highEnchantment;
51	};
52	
53	const nonComponentBaseFor = (items: Item[]): number =>
54	  items.reduce((sum, item) => {
55	    const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type];
56	    return sum + base + surchargesFor(item, base);
57	  }, 0);
58	
59	const LOYALTY_DISCOUNT_RATE = 0.2;
60	const LOYALTY_THRESHOLD_YEARS = 2;
61	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
62	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
63	
64	const loyaltyDiscountFor = (yearsWithMHPCO: number, policyBase: number): number =>
65	  yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
66	
67	const followUpDiscountFor = (apply: boolean | undefined, policyBase: number): number =>
68	  apply ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
69	
70	const sumOfItemBases = (items: Item[]): number =>
71	  items.reduce((sum, item) => sum + BASE_PREMIUM_BY_ITEM_TYPE[item.type], 0);
72	
73	const firstInsuranceSurchargeFor = (apply: boolean | undefined, items: Item[]): number =>
74	  apply ? sumOfItemBases(items) * FIRST_INSURANCE_SURCHARGE_RATE : 0;
75	
76	const policyBaseFor = (items: Item[]): number => {
77	  const components = items.filter(isComponent);
78	  const nonComponents = items.filter((item) => !isComponent(item));
79	  return nonComponentBaseFor(nonComponents) + componentsBaseFor(components);
80	};
81	
82	type Damage = { itemType: string; amount: number };
83	
84	const DEDUCTIBLE = 100;
85	
86	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
87	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
88	
89	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
90	  sword: 1000,
91	  amulet: 600,
92	  staff: 800,
93	  potion: 400,
94	  rune: 250,
95	  moonstone: 250,
96	};
97	
98	const CAP_MULTIPLIER = 2;
99	
100	const reimbursableAmountFor = (damage: Damage, item: Item | undefined): number =>
101	  item && item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
102	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
103	    : damage.amount;
104	
105	const rawPayoutFor = (items: Item[], damages: Damage[]): number =>
106	  damages.reduce((sum, damage) => {
107	    const item = items.find((i) => i.type === damage.itemType);
108	    return sum + reimbursableAmountFor(damage, item) - DEDUCTIBLE;
109	  }, 0);
110	
111	const insuranceSumFor = (items: Item[]): number =>
112	  items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type], 0);
113	
114	const validateDamagesAgainstItems = (items: Item[], damages: Damage[]): void => {
115	  const itemCounts = countByType(items);
116	  const damageCounts = countBy(damages, (damage) => damage.itemType);
117	  for (const [type, count] of damageCounts) {
118	    if (count > (itemCounts.get(type) ?? 0)) {
119	      throw new Error(`More damages of type ${type} than insured items`);
120	    }
121	  }
122	};
123	
124	const validateDamageAmounts = (damages: Damage[]): void => {
125	  for (const damage of damages) {
126	    if (damage.amount < 0) {
127	      throw new Error(`Negative damage amount: ${damage.amount}`);
128	    }
129	  }
130	};
