import { readFileSync } from "node:fs";
import { quote, claim } from "./claim-office.js";

type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type Damage = { itemType: string; amount: number };
type Step =
  | { op: "quote"; items: Item[] }
  | { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const STDIN_FD = 0;

const processStep = (step: Step, yearsWithMHPCO: number, steps: Step[]): object => {
  if (step.op === "quote") {
    return { premium: quote({ yearsWithMHPCO, items: step.items }) };
  }
  const referenced = steps[step.policy];
  if (referenced.op !== "quote") return {};
  return claim({ items: referenced.items, damages: step.incident.damages });
};

const scenario: Scenario = JSON.parse(readFileSync(STDIN_FD, "utf-8"));
const results = scenario.steps.map((step) =>
  processStep(step, scenario.customer.yearsWithMHPCO, scenario.steps)
);
process.stdout.write(JSON.stringify({ results }));
